import{_ as e,o as i,c as r,ag as t}from"./chunks/framework.sFGfN9OF.js";const c=JSON.parse('{"title":"Redis 缓存设计","description":"","frontmatter":{},"headers":[],"relativePath":"middleware/redis.md","filePath":"middleware/redis.md","lastUpdated":1776563650000}'),l={name:"middleware/redis.md"};function o(d,a,s,n,m,p){return i(),r("div",null,[...a[0]||(a[0]=[t('<h1 id="redis-缓存设计" tabindex="-1">Redis 缓存设计 <a class="header-anchor" href="#redis-缓存设计" aria-label="Permalink to &quot;Redis 缓存设计&quot;">​</a></h1><h2 id="problem" tabindex="-1">Problem <a class="header-anchor" href="#problem" aria-label="Permalink to &quot;Problem&quot;">​</a></h2><p>高并发系统中使用 Redis 时，如何避免缓存穿透、击穿和雪崩？</p><h2 id="explanation" tabindex="-1">Explanation <a class="header-anchor" href="#explanation" aria-label="Permalink to &quot;Explanation&quot;">​</a></h2><p>缓存问题的本质是请求流量和后端承载能力不匹配。缓存穿透通常由不存在的数据反复查询引起，可以通过布隆过滤器或空值缓存缓解；缓存击穿常见于热点 Key 过期瞬间，可以通过互斥锁、逻辑过期或热点永不过期策略处理；缓存雪崩则是大量 Key 同时失效，需要通过过期时间打散、限流降级和多级缓存来降低冲击。</p><p>除了命中率，还要关注缓存一致性。对于读多写少场景，常见做法是更新数据库后删除缓存；如果一致性要求高，还需要配合消息队列、重试机制或订阅 binlog 做异步修复。</p><h2 id="key-points" tabindex="-1">Key Points <a class="header-anchor" href="#key-points" aria-label="Permalink to &quot;Key Points&quot;">​</a></h2><ul><li>穿透、击穿、雪崩的成因和治理策略不同。</li><li>热点数据需要单独设计过期与重建机制。</li><li>删除缓存要考虑并发写和延迟双删等问题。</li><li>监控命中率、慢查询和内存淘汰策略很关键。</li></ul><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Redis 不只是一个高性能 KV 存储，更是系统稳定性的关键缓冲层。缓存方案设计得好，后端系统的抗压能力会有明显提升。</p>',10)])])}const u=e(l,[["render",o]]);export{c as __pageData,u as default};
